1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  priorContracts: number;
4	};
5	
6	export type Item = Record<string, unknown>;
7	
8	export type Policy = {
9	  customer: Customer;
10	  items: Item[];
11	};
12	
13	export type QuoteResult = {
14	  premium: number;
15	};
16	
17	export type ClaimResult = {
18	  payout: number;
19	  remainingCap: number;
20	};
21	
22	const PROCESSING_FEE = 5;
23	const COMPONENT_BASE_PREMIUM = 25;
24	const COMPONENT_BLOCK_SIZE = 3;
25	const COMPONENT_BLOCK_PREMIUM = 60;
26	
27	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
28	  sword: 100,
29	  amulet: 60,
30	  staff: 80,
31	  potion: 40,
32	  component: COMPONENT_BASE_PREMIUM,
33	};
34	
35	const basePremiumForItem = (item: Item): number =>
36	  BASE_PREMIUM_BY_ITEM_TYPE[item.type as string] ?? 0;
37	
38	const isComponent = (item: Item): boolean => item.type === "component";
39	
40	const groupComponentsByType = (items: Item[]): Map<string, number> => {
41	  const groups = new Map<string, number>();
42	  for (const item of items.filter(isComponent)) {
43	    const key = item.componentType as string;
44	    groups.set(key, (groups.get(key) ?? 0) + 1);
45	  }
46	  return groups;
47	};
48	
49	const componentGroupPremium = (count: number): number =>
50	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_BASE_PREMIUM;
51	
52	const componentsPremium = (items: Item[]): number =>
53	  Array.from(groupComponentsByType(items).values()).reduce(
54	    (sum, count) => sum + componentGroupPremium(count),
55	    0,
56	  );
57	
58	const CURSE_SURCHARGE_RATE = 0.5;
59	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
60	const HIGH_ENCHANTMENT_THRESHOLD = 5;
61	
62	type ItemModifier = (item: Item, base: number) => number;
63	
64	const curseModifier: ItemModifier = (item, base) =>
65	  item.cursed === true ? base * CURSE_SURCHARGE_RATE : 0;
66	
67	const highEnchantmentModifier: ItemModifier = (item, base) =>
68	  (item.enchantment as number) >= HIGH_ENCHANTMENT_THRESHOLD
69	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
70	    : 0;
71	
72	const ITEM_MODIFIERS: ItemModifier[] = [curseModifier, highEnchantmentModifier];
73	
74	const itemPremium = (item: Item): number => {
75	  const base = basePremiumForItem(item);
76	  return ITEM_MODIFIERS.reduce(
77	    (premium, modifier) => premium + modifier(item, base),
78	    base,
79	  );
80	};
81	
82	const nonComponentsPremium = (items: Item[]): number =>
83	  items
84	    .filter((item) => !isComponent(item))
85	    .reduce((sum, item) => sum + itemPremium(item), 0);
86	
87	const nonComponentsBasePremium = (items: Item[]): number =>
88	  items
89	    .filter((item) => !isComponent(item))
90	    .reduce((sum, item) => sum + basePremiumForItem(item), 0);
91	
92	const LOYALTY_DISCOUNT_RATE = 0.2;
93	const LOYALTY_YEARS_THRESHOLD = 2;
94	
95	const loyaltyAdjustment = (customer: Customer, basePremium: number): number =>
96	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
97	    ? -basePremium * LOYALTY_DISCOUNT_RATE
98	    : 0;
99	
100	export function quote(policy: Policy): QuoteResult {
101	  const componentsTotal = componentsPremium(policy.items);
102	  const itemsTotal = nonComponentsPremium(policy.items) + componentsTotal;
103	  const policyBase = nonComponentsBasePremium(policy.items) + componentsTotal;
104	  const policyAdjustments = loyaltyAdjustment(policy.customer, policyBase);
105	  return { premium: itemsTotal + policyAdjustments + PROCESSING_FEE };
106	}
107	
108	export function claim(..._args: unknown[]): ClaimResult {
109	  return undefined as unknown as ClaimResult;
110	}
